// SM4 CBC 模式加密示例
func sm4Encrypt(plaintext: ByteArray, key: ByteArray, iv: ByteArray): ByteArray {
    let cipher = SM4Cipher(mode: CipherMode.CBC, padding: Padding.PKCS7)
    cipher.init(CipherOp.ENCRYPT, key, iv)
    return cipher.update(plaintext) + cipher.final()
}
// 解密示例
func sm4Decrypt(ciphertext: ByteArray, key: ByteArray, iv: ByteArray): ByteArray {
    let cipher = SM4Cipher(mode: CipherMode.CBC, padding: Padding.PKCS7)
    cipher.init(CipherOp.DECRYPT, key, iv)
    return cipher.update(ciphertext) + cipher.final()
}

